Approach ACK 666643be8fcdbf587f8fd18edea064ee3c547936

`grep -rn 'SetMockTime' src/test/fuzz/ src/wallet/test/fuzz/` shows several remaining calls. Of those, these two follow the same `ConsumeTime` pattern and could be included:

- `src/test/fuzz/block_index_tree.cpp:44`
- `src/wallet/test/fuzz/fees.cpp:65`

Built with libfuzzer, verified both targets pass with this diff applied:

```diff
bitcoin pr-34479 !❄ ❯ git diff -U1
diff --git a/src/test/fuzz/block_index_tree.cpp b/src/test/fuzz/block_index_tree.cpp
index a4bbe95840..bff8eafa92 100644
--- a/src/test/fuzz/block_index_tree.cpp
+++ b/src/test/fuzz/block_index_tree.cpp
@@ -14,2 +14,3 @@
 #include <test/util/setup_common.h>
+#include <test/util/time.h>
 #include <test/util/validation.h>
@@ -43,3 +44,3 @@ FUZZ_TARGET(block_index_tree, .init = initialize_block_index_tree)
     FuzzedDataProvider fuzzed_data_provider(buffer.data(), buffer.size());
-    SetMockTime(ConsumeTime(fuzzed_data_provider));
+    NodeClockContext clock_ctx{ConsumeTime(fuzzed_data_provider)};
     auto& chainman = static_cast<TestChainstateManager&>(*g_setup->m_node.chainman);
diff --git a/src/wallet/test/fuzz/fees.cpp b/src/wallet/test/fuzz/fees.cpp
index 6d9de0cc0f..03a5e2abc9 100644
--- a/src/wallet/test/fuzz/fees.cpp
+++ b/src/wallet/test/fuzz/fees.cpp
@@ -8,2 +8,3 @@
 #include <test/util/setup_common.h>
+#include <test/util/time.h>
 #include <test/util/txmempool.h>
@@ -64,3 +65,3 @@ FUZZ_TARGET(wallet_fees, .init = initialize_setup)
     FuzzedDataProvider fuzzed_data_provider{buffer.data(), buffer.size()};
-    SetMockTime(ConsumeTime(fuzzed_data_provider));
+    NodeClockContext clock_ctx{ConsumeTime(fuzzed_data_provider)};
     auto& node{g_setup->m_node};
```
